import fs from "fs"
import path from "path"
import crypto from "crypto"

const STATE_PATH = path.join(
  process.cwd(),
  "data",
  "listing-state.json"
)

interface ListingState {
  externalId: string
  fingerprint: string
}

/**
 * Ensure state file exists
 */
function ensureStateFile() {
  if (!fs.existsSync("data")) {
    fs.mkdirSync("data")
  }

  if (!fs.existsSync(STATE_PATH)) {
    fs.writeFileSync(STATE_PATH, JSON.stringify([]))
  }
}

/**
 * Load stored listing states
 */
function loadStates(): Map<string, string> {
  ensureStateFile()
  const raw = fs.readFileSync(STATE_PATH, "utf-8")
  const items: ListingState[] = JSON.parse(raw)

  return new Map(items.map((i) => [i.externalId, i.fingerprint]))
}

/**
 * Save updated states
 */
function saveStates(stateMap: Map<string, string>) {
  const data: ListingState[] = Array.from(stateMap.entries()).map(
    ([externalId, fingerprint]) => ({
      externalId,
      fingerprint,
    })
  )

  fs.writeFileSync(STATE_PATH, JSON.stringify(data, null, 2))
}

/**
 * Create fingerprint from material fields
 */
function createFingerprint(listing: any): string {
  const materialFields = {
    price: listing.price,
    beds: listing.beds,
    baths: listing.baths,
    squareFeet: listing.squareFeet,
    status: listing.status,
  }

  return crypto
    .createHash("sha256")
    .update(JSON.stringify(materialFields))
    .digest("hex")
}

/**
 * Determine if listing has changed
 */
export function detectChanges(listing: any): boolean {
  const states = loadStates()
  const fingerprint = createFingerprint(listing)

  const previousFingerprint = states.get(listing.externalId)

  // New listing
  if (!previousFingerprint) {
    states.set(listing.externalId, fingerprint)
    saveStates(states)
    return true
  }

  // Changed listing
  if (previousFingerprint !== fingerprint) {
    states.set(listing.externalId, fingerprint)
    saveStates(states)
    return true
  }

  // Unchanged listing
  return false
}
